+        assert_eq!(d.handles().live_count(), 2);
+
+        d.scope_close(&s1, None).unwrap();
+        assert_eq!(d.handles().live_count(), 1);
+
+        d.runtime_close(&rt, None).unwrap();
+        assert_eq!(d.handles().live_count(), 0);
+    }
